  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { listen } from "@tauri-apps/api/event";
  4→import { useQueryClient } from "@tanstack/react-query";
  5→import { Sidebar } from "./features/repos/Sidebar";
  6→import { useReposQuery } from "./hooks/use-tauri-query";
  7→import { TitleBar } from "./components/TitleBar";
  8→import { TabBar } from "./components/TabBar";
  9→import { CheckpointList } from "./features/checkpoints/CheckpointList";
 10→import { TranscriptView } from "./features/transcripts/TranscriptView";
 11→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
 12→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 13→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 14→import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 15→import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 16→import { XtermTerminal } from "./features/terminal/XtermTerminal";
 17→import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
 18→import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
 19→import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
 20→import { useLiveUpdates } from "./hooks/use-live-updates";
 21→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 22→import { ArrowLeft, GitCommit } from "lucide-react";
 23→
 24→export interface Tab {
 25→  id: string;
 26→  branch: string;
 27→  repoPath: string;
 28→  worktree: WorktreeInfo | null;
 29→  kind: "branch" | "agent";
 30→  agent: string | null;
 31→  hasActiveSession: boolean;
 32→}
 33→
 34→function resolveAgent(agent: string) {
 35→  if (agent === "codex") return "codex";
 36→  if (agent === "gemini") return "gemini";
 37→  if (agent === "cursor") return "cursor";
 38→  return "claude-code";
 39→}
 40→
 41→export default function App() {
 42→  const [tabs, setTabs] = useState<Tab[]>([
 43→    {
 44→      id: "main",
 45→      branch: "main",
 46→      repoPath: "",
 47→      worktree: null,
 48→      kind: "branch",
 49→      agent: null,
 50→      hasActiveSession: false,
 51→    },
 52→  ]);
 53→  const [activeTabId, setActiveTabId] = useState("main");
 54→  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
 55→  const [innerTab, setInnerTab] = useState<
 56→    "chat" | "checkpoints" | "diff" | "insights" | "debug"
 57→  >("chat");
 58→  const [selectedCheckpoint, setSelectedCheckpoint] =
 59→    useState<CheckpointSummary | null>(null);
 60→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 61→    "transcript" | "diff" | "insights" | "debug"
 62→  >("transcript");
 63→
 64→  // Maps tab ID → PTY session ID for the chat terminal
 65→  const [chatPtySessions, setChatPtySessions] = useState<Map<string, string>>(
 66→    () => new Map()
 67→  );
 68→  const chatPtySessionsRef = useRef(chatPtySessions);
 69→  chatPtySessionsRef.current = chatPtySessions;
 70→
 71→  // Track which tabs are actively producing PTY output ("busy")
 72→  const [busyTabIds, setBusyTabIds] = useState<Set<string>>(() => new Set());
 73→  const busyTimersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());
 74→
 75→  // Global pty-output listener to detect tab activity
 76→  useEffect(() => {
 77→    const unlisten = listen<{ session_id: string; data: string }>("pty-output", (event) => {
 78→      const sessionId = event.payload.session_id;
 79→      // Reverse-map session_id → tabId
 80→      const sessions = chatPtySessionsRef.current;
 81→      let tabId: string | null = null;
 82→      for (const [tid, sid] of sessions.entries()) {
 83→        if (sid === sessionId) { tabId = tid; break; }
 84→      }
 85→      if (!tabId) return;
 86→
 87→      const tid = tabId; // capture for closures
 88→      setBusyTabIds((prev) => {
 89→        if (prev.has(tid)) return prev;
 90→        const next = new Set(prev);
 91→        next.add(tid);
 92→        return next;
 93→      });
 94→
 95→      // Reset the idle timer for this tab
 96→      const existing = busyTimersRef.current.get(tid);
 97→      if (existing) clearTimeout(existing);
 98→      busyTimersRef.current.set(
 99→        tid,
100→        setTimeout(() => {
101→          setBusyTabIds((prev) => {
102→            if (!prev.has(tid)) return prev;
103→            const next = new Set(prev);
104→            next.delete(tid);
105→            return next;
106→          });
107→          busyTimersRef.current.delete(tid);
108→        }, 3000)
109→      );
110→    });
111→
112→    return () => {
113→      unlisten.then((fn) => fn());
114→      // Clear all timers
115→      for (const timer of busyTimersRef.current.values()) clearTimeout(timer);
116→      busyTimersRef.current.clear();
117→    };
118→  }, []);
119→
120→  // Load repos so we can auto-populate the initial tab
121→  const queryClient = useQueryClient();
122→  const { data: repos } = useReposQuery();
123→
124→  // Auto-populate the initial tab's repoPath from the first discovered repo
125→  useEffect(() => {
126→    if (!repos || repos.length === 0) return;
127→    setTabs((prev) => {
128→      const updated = prev.map((tab) => {
129→        if (tab.id === "main" && !tab.repoPath) {
130→          const repo = repos[0];
131→          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
132→          return {
133→            ...tab,
134→            repoPath: repo.path,
135→            branch: headBranch?.name ?? repo.branches[0]?.name ?? "main",
136→          };
137→        }
138→        return tab;
139→      });
140→      return updated;
141→    });
142→  }, [repos]);
143→
144→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
145→  const tabsWithSessions = tabs.map((tab) => ({
146→    ...tab,
147→    hasActiveSession: chatPtySessions.has(tab.id),
148→  }));
149→
150→  // Live updates — watch active repo for checkpoint/session changes
151→  useLiveUpdates(activeTab.repoPath);
152→
153→  // Auto-spawn a PTY shell when the Chat tab is active and no session exists
154→  useEffect(() => {
155→    if (innerTab !== "chat") return;
156→    if (!activeTab.repoPath) return;
157→    if (chatPtySessionsRef.current.has(activeTabId)) return;
158→
159→    // Spawn a shell PTY for this tab
160→    invoke<string>("pty_create", {
161→      workingDir: activeTab.repoPath,
162→    })
163→      .then((sessionId) => {
164→        setChatPtySessions((prev) => {
165→          const next = new Map(prev);
166→          next.set(activeTabId, sessionId);
167→          return next;
168→        });
169→      })
170→      .catch((err) => {
171→        console.error("[chat] pty_create FAILED:", err);
172→      });
173→  }, [innerTab, activeTabId, activeTab.repoPath]);
174→
175→  // Agent dispatch — spawn Claude in a PTY for the Chat tab
176→  const handleSendToAgent = useCallback(
177→    async (agent: string, prompt: string) => {
178→      if (!activeTab.repoPath) return;
179→
180→      const resolvedAgent = resolveAgent(agent);
181→
182→      // If current tab already has a PTY, write the prompt to it
183→      const existingPty = chatPtySessionsRef.current.get(activeTabId);
184→      if (existingPty && prompt) {
185→        setInnerTab("chat");
186→        await invoke("pty_write", {
187→          sessionId: existingPty,
188→          data: prompt + "\n",
189→        }).catch(console.error);
190→        return;
191→      }
192→
193→      // Create a new agent tab
194→      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
195→      const agentTab: Tab = {
196→        id: tabId,
197→        branch: activeTab.branch,
198→        repoPath: activeTab.repoPath,
199→        worktree: activeTab.worktree,
200→        kind: "agent",
201→        agent: resolvedAgent,
202→        hasActiveSession: false,
203→      };
204→      setTabs((prev) => [...prev, agentTab]);
205→      setActiveTabId(tabId);
206→      setInnerTab("chat");
207→
208→      // Spawn a PTY running the agent
209→      try {
210→        const sessionId = await invoke<string>("pty_create", {
211→          workingDir: activeTab.repoPath,
212→          command: resolvedAgent,
213→          initialInput: prompt ? prompt + "\n" : undefined,
214→        });
215→        setChatPtySessions((prev) => {
216→          const next = new Map(prev);
217→          next.set(tabId, sessionId);
218→          return next;
219→        });
220→      } catch (err) {
221→        console.error("[chat] pty_create FAILED:", err);
222→      }
223→    },
224→    [activeTab, activeTabId]
225→  );
226→
227→  // Parallel agent — creates a dedicated worktree, then spawns the agent in it
228→  const handleSpawnParallelAgent = useCallback(
229→    async (agent: string) => {
230→      if (!activeTab.repoPath) return;
231→
232→      const resolvedAgent = resolveAgent(agent);
233→
234→      // Create a worktree with auto-generated branch
235→      try {
236→        const { branch, worktree_path } = await invoke<{
237→          branch: string;
238→          worktree_path: string;
239→        }>("create_agent_worktree", {
240→          repoPath: activeTab.repoPath,
241→          agent: resolvedAgent,
242→        });
243→
244→        const tabId = `agent:${resolvedAgent}:${Date.now()}`;
245→        const agentTab: Tab = {
246→          id: tabId,
247→          branch,
248→          repoPath: worktree_path,
249→          worktree: { path: worktree_path, branch, is_main: false },
250→          kind: "agent",
251→          agent: resolvedAgent,
252→          hasActiveSession: false,
253→        };
254→        setTabs((prev) => [...prev, agentTab]);
255→        setActiveTabId(tabId);
256→        setInnerTab("chat");
257→
258→        // Refresh sidebar to show the new worktree
259→        queryClient.invalidateQueries({ queryKey: ["repos"] });
260→
261→        // Spawn the agent PTY in the worktree directory
262→        const sessionId = await invoke<string>("pty_create", {
263→          workingDir: worktree_path,
264→          command: resolvedAgent,
265→        });
266→        setChatPtySessions((prev) => {
267→          const next = new Map(prev);
268→          next.set(tabId, sessionId);
269→          return next;
270→        });
271→      } catch (err) {
272→        console.error("[parallel-agent] Failed:", err);
273→      }
274→    },
275→    [activeTab]
276→  );
277→
278→  // Clear selected checkpoint when switching branch tabs
279→  useEffect(() => {
280→    setSelectedCheckpoint(null);
281→    setCheckpointInnerTab("transcript");
282→  }, [activeTabId]);
283→
284→  // Keyboard shortcuts
285→  useEffect(() => {
286→    function onKeyDown(e: KeyboardEvent) {
287→      const meta = e.metaKey || e.ctrlKey;
288→
289→      // Cmd+K = focus search
290→      if (meta && e.key === "k") {
291→        e.preventDefault();
292→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
293→      }
294→      // Cmd+W = close active tab
295→      if (meta && e.key === "w") {
296→        e.preventDefault();
297→        handleCloseTab(activeTabId);
298→      }
299→      // Cmd+1-9 = switch to tab by index
300→      if (meta && e.key >= "1" && e.key <= "9") {
301→        e.preventDefault();
302→        const idx = parseInt(e.key) - 1;
303→        if (idx < tabs.length) {
304→          setActiveTabId(tabs[idx].id);
305→        }
306→      }
307→      // Cmd+[ / Cmd+] = prev/next tab
308→      if (meta && e.key === "[") {
309→        e.preventDefault();
310→        const idx = tabs.findIndex((t) => t.id === activeTabId);
311→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
312→      }
313→      if (meta && e.key === "]") {
314→        e.preventDefault();
315→        const idx = tabs.findIndex((t) => t.id === activeTabId);
316→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
317→      }
318→      // Escape = deselect checkpoint
319→      if (e.key === "Escape" && selectedCheckpoint) {
320→        setSelectedCheckpoint(null);
321→      }
322→    }
323→    window.addEventListener("keydown", onKeyDown);
324→    return () => window.removeEventListener("keydown", onKeyDown);
325→  }, [activeTabId, tabs, selectedCheckpoint]);
326→
327→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
328→    const newTab = createBranchTab(branch, repoPath);
329→    const existing = tabs.find(
330→      (t) =>
331→        t.kind === "branch" &&
332→        t.branch === newTab.branch &&
333→        t.repoPath === newTab.repoPath
334→    );
335→    if (existing) {
336→      setActiveTabId(existing.id);
337→    } else {
338→      setTabs([...tabs, newTab]);
339→      setActiveTabId(newTab.id);
340→    }
341→  }
342→
343→  function handleWorktreeSelect(wt: WorktreeInfo) {
344→    const newTab = createWorktreeTab(wt);
345→    const existing = tabs.find(
346→      (t) =>
347→        t.kind === "branch" &&
348→        t.branch === newTab.branch &&
349→        t.repoPath === newTab.repoPath
350→    );
351→    if (existing) {
352→      setActiveTabId(existing.id);
353→    } else {
354→      setTabs([...tabs, newTab]);
355→      setActiveTabId(newTab.id);
356→    }
357→  }
358→
359→  function handleCloseTab(tabId: string) {
360→    if (tabs.length <= 1) return;
361→    const idx = tabs.findIndex((t) => t.id === tabId);
362→    const newTabs = tabs.filter((t) => t.id !== tabId);
363→    setTabs(newTabs);
364→    if (activeTabId === tabId) {
365→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
366→    }
367→    // Destroy the chat PTY session for this tab
368→    const chatPtyId = chatPtySessionsRef.current.get(tabId);
369→    if (chatPtyId) {
370→      invoke("pty_destroy", { sessionId: chatPtyId }).catch(console.error);
371→    }
372→    setChatPtySessions((prev) => {
373→      if (!prev.has(tabId)) return prev;
374→      const next = new Map(prev);
375→      next.delete(tabId);
376→      return next;
377→    });
378→  }
379→
380→  function handleBranchDeleted(branchName: string, repoPath: string) {
381→    const tabsToRemove = tabs.filter(
382→      (tab) =>
383→        tab.kind === "branch" &&
384→        tab.worktree === null &&
385→        tab.branch === branchName &&
386→        tab.repoPath === repoPath
387→    );
388→
389→    if (tabsToRemove.length === 0) return;
390→
391→    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
392→    setTabs(nextTabs);
393→
394→    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
395→      setActiveTabId(nextTabs[0].id);
396→    }
397→
398→    setChatPtySessions((prev) => {
399→      const next = new Map(prev);
400→      for (const tab of tabsToRemove) {
401→        const ptyId = next.get(tab.id);
402→        if (ptyId) {
403→          invoke("pty_destroy", { sessionId: ptyId }).catch(console.error);
404→          next.delete(tab.id);
405→        }
406→      }
407→      return next;
408→    });
409→  }
410→
411→  function handleWorktreeDeleted(worktreePath: string) {
412→    const cleanup = planWorktreeDeletionCleanup({
413→      tabs,
414→      activeTabId,
415→      worktreePath,
416→    });
417→
418→    if (cleanup.removedTabIds.length === 0) return;
419→
420→    setTabs(cleanup.remainingTabs);
421→
422→    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
423→      setActiveTabId(cleanup.nextActiveTabId);
424→    }
425→
426→    setChatPtySessions((prev) => {
427→      const next = new Map(prev);
428→      for (const tabId of cleanup.removedTabIds) {
429→        const ptyId = next.get(tabId);
430→        if (ptyId) {
431→          invoke("pty_destroy", { sessionId: ptyId }).catch(console.error);
432→          next.delete(tabId);
433→        }
434→      }
435→      return next;
436→    });
437→  }
438→
439→  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
440→    e.preventDefault();
441→    const startX = e.clientX;
442→    const startWidth = sidebarWidth;
443→
444→    function onMouseMove(ev: MouseEvent) {
445→      const delta = ev.clientX - startX;
446→      setSidebarWidth(clampSidebarWidth(startWidth + delta));
447→    }
448→
449→    function onMouseUp() {
450→      window.removeEventListener("mousemove", onMouseMove);
451→      window.removeEventListener("mouseup", onMouseUp);
452→    }
453→
454→    window.addEventListener("mousemove", onMouseMove);
455→    window.addEventListener("mouseup", onMouseUp);
456→  }
457→
458→  const repoName = activeTab.repoPath
459→    ? activeTab.repoPath.split("/").pop()
460→    : "";
461→
462→  return (
463→    <div className="flex h-screen flex-col">
464→      <TitleBar
465→        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
466→      />
467→
468→      <div className="flex flex-1 overflow-hidden">
469→        {/* Sidebar */}
470→        <Sidebar
471→          activeTab={activeTab}
472→          width={sidebarWidth}
473→          busyTabIds={busyTabIds}
474→          tabs={tabs}
475→          onBranchSelect={handleBranchSelect}
476→          onBranchDeleted={handleBranchDeleted}
477→          onWorktreeDeleted={handleWorktreeDeleted}
478→          onWorktreeSelect={handleWorktreeSelect}
479→          onResizeStart={handleSidebarResizeStart}
480→        />
481→
482→        {/* Main content */}
483→        <div className="flex min-w-0 flex-1 flex-col overflow-hidden">
484→          <TabBar
485→            tabs={tabsWithSessions}
486→            activeTabId={activeTabId}
487→            busyTabIds={busyTabIds}
488→            onSelectTab={setActiveTabId}
489→            onCloseTab={handleCloseTab}
490→            onAddAgentTab={(agent) => handleSendToAgent(agent, "")}
491→            onAddParallelAgent={handleSpawnParallelAgent}
492→          />
493→
494→          <div className="flex min-w-0 flex-1 flex-col overflow-hidden">
495→            {/* Inner tabs */}
496→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
497→              {(["chat", "checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
498→                <button
499→                  key={tab}
500→                  onClick={() => setInnerTab(tab)}
501→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${innerTab === tab
502→                    ? "border-accent text-fg"
503→                    : "border-transparent text-fg-subtle hover:text-fg-muted"
504→                    }`}
505→                >
506→                  {tab === "chat"
507→                    ? "Chat"
508→                    : tab === "checkpoints"
509→                      ? "Checkpoints"
510→                      : tab === "diff"
511→                        ? "Diff"
512→                        : tab === "insights"
513→                          ? "Insights"
514→                          : "Debug"}
515→                </button>
516→              ))}
517→            </div>
518→
519→            {/* Main view */}
520→            <div className="flex flex-1 overflow-hidden bg-bg">
521→              {/* Render one terminal per tab with a PTY — keep mounted, show/hide via CSS */}
522→              {Array.from(chatPtySessions.entries()).map(([tabId, ptySessionId]) => (
523→                <div
524→                  key={tabId}
525→                  className="flex flex-1 overflow-hidden"
526→                  style={{
527→                    display: innerTab === "chat" && tabId === activeTabId ? "flex" : "none",
528→                  }}
529→                >
530→                  <XtermTerminal sessionId={ptySessionId} />
531→                </div>
532→              ))}
533→              {innerTab === "checkpoints" && (
534→                <>
535→                  {/* Checkpoint list — always visible when on checkpoints tab */}
536→                  <div
537→                    className={`min-w-0 overflow-y-auto overflow-x-hidden ${selectedCheckpoint
538→                      ? "w-[320px] shrink-0 border-r border-border-subtle"
539→                      : "flex-1"
540→                      }`}
541→                  >
542→                    <CheckpointList
543→                      repoPath={activeTab.repoPath}
544→                      branch={activeTab.branch}
545→                      onSelectCheckpoint={(cp) => {
546→                        setSelectedCheckpoint(cp);
547→                        setCheckpointInnerTab("transcript");
548→                      }}
549→                    />
550→                  </div>
551→
552→                  {/* Checkpoint detail panel */}
553→                  {selectedCheckpoint && (
554→                    <div className="flex flex-1 flex-col overflow-hidden">
555→                      {/* Detail header */}
556→                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
557→                        <button
558→                          onClick={() => setSelectedCheckpoint(null)}
559→                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
560→                        >
561→                          <ArrowLeft size={14} />
562→                        </button>
563→                        <GitCommit size={14} className="text-fg-subtle" />
564→                        <span className="truncate text-xs font-medium text-fg">
565→                          {selectedCheckpoint.commit_message || "Untitled"}
566→                        </span>
567→                        <span className="font-mono text-xs text-fg-subtle">
568→                          {selectedCheckpoint.commit_sha
569→                            ? selectedCheckpoint.commit_sha.slice(0, 7)
570→                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
571→                        </span>
572→                      </div>
573→
574→                      {/* Checkpoint sub-tabs */}
575→                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
576→                        {(["transcript", "diff", "insights", "debug"] as const).map(
577→                          (tab) => (
578→                            <button
579→                              key={tab}
580→                              onClick={() => setCheckpointInnerTab(tab)}
581→                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${checkpointInnerTab === tab
582→                                ? "border-accent text-fg"
583→                                : "border-transparent text-fg-subtle hover:text-fg-muted"
584→                                }`}
585→                            >
586→                              {tab === "transcript"
587→                                ? "Transcript"
588→                                : tab === "diff"
589→                                  ? "Diff"
590→                                  : tab === "insights"
591→                                    ? "Insights"
592→                                    : "Debug"}
593→                            </button>
594→                          )
595→                        )}
596→                      </div>
597→
598→                      {/* Checkpoint detail content */}
599→                      <div className="flex-1 overflow-y-auto">
600→                        {checkpointInnerTab === "transcript" && (
601→                          <TranscriptView
602→                            repoPath={activeTab.repoPath}
603→                            checkpoint={selectedCheckpoint}
604→                          />
605→                        )}
606→                        {checkpointInnerTab === "diff" && (
607→                          <DiffView
608→                            repoPath={activeTab.repoPath}
609→                            checkpoint={selectedCheckpoint}
610→                            onSendToAgent={handleSendToAgent}
611→                          />
612→                        )}
613→                        {checkpointInnerTab === "insights" && (
614→                          <CheckpointInsightsContainer
615→                            repoPath={activeTab.repoPath}
616→                            checkpoint={selectedCheckpoint}
617→                          />
618→                        )}
619→                        {checkpointInnerTab === "debug" && (
620→                          <CheckpointDebugContainer
621→                            repoPath={activeTab.repoPath}
622→                            checkpoint={selectedCheckpoint}
623→                          />
