 40→#[tauri::command]
 41→fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 42→    let repo_paths = config::discover_repos();
 43→    let registered = config::get_registered_repos();
 44→    let registered_set: HashSet<String> = registered.into_iter().collect();
 45→    let mut repos = Vec::new();
 46→    for path in repo_paths {
 47→        match git::get_repo_info(&path) {
 48→            Ok(mut info) => {
 49→                info.registered = registered_set.contains(&path);
 50→                repos.push(info);
 51→            }
 52→            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 53→        }
 54→    }
 55→    Ok(repos)
