144→#[tauri::command]
145→fn get_transcript(
146→    repo_path: String,
147→    checkpoint_id: String,
148→    session_index: u32,
149→) -> Result<Vec<session::TranscriptMessage>, String> {
150→    let repo = git::open_repo(&repo_path)?;
151→
152→    let prefix = &checkpoint_id[..2];
153→    let suffix = &checkpoint_id[2..];
154→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
155→    let meta_content = read_blob(&repo, &meta_path).ok();
156→    let candidates =
157→        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
158→
159→    for path in &candidates {
160→        if let Ok(content) = read_blob(&repo, path) {
161→            return Ok(session::read_transcript(&content));
162→        }
163→    }
164→
165→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
166→}
167→
168→fn transcript_candidate_paths(
169→    checkpoint_id: &str,
170→    session_index: u32,
171→    meta_content: Option<&str>,
172→) -> Vec<String> {
173→    let prefix = &checkpoint_id[..2];
174→    let suffix = &checkpoint_id[2..];
175→    let requested_session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
176→    let mut candidates = Vec::new();
177→
178→    let mut push_candidate = |path: String| {
179→        if !path.is_empty() && !candidates.contains(&path) {
180→            candidates.push(path);
181→        }
182→    };
183→
184→    if let Some(meta_content) = meta_content {
185→        if let Ok(meta) = serde_json::from_str::<serde_json::Value>(meta_content) {
186→            if let Some(sessions) = meta.get("sessions").and_then(|s| s.as_array()) {
187→                let mut ordered_sessions = Vec::new();
188→                if let Some(session) = sessions.get(session_index as usize) {
189→                    ordered_sessions.push(session);
190→                }
191→                for (idx, session) in sessions.iter().enumerate() {
192→                    if idx != session_index as usize {
193→                        ordered_sessions.push(session);
194→                    }
195→                }
196→
197→                for session in ordered_sessions {
198→                    if let Some(path) = session.get("transcript").and_then(|p| p.as_str()) {
199→                        push_candidate(path.trim_start_matches('/').to_string());
200→                    }

