 12→/** Group checkpoints by calendar date, e.g. "Thursday 12 Mar" */
 13→function groupByDate(
 14→  checkpoints: CheckpointSummary[],
 15→): { label: string; items: CheckpointSummary[] }[] {
 16→  const groups = new Map<string, CheckpointSummary[]>();
 17→  for (const cp of checkpoints) {
 18→    const d = new Date(cp.created_at);
 19→    const key = d.toDateString(); // consistent grouping key
 20→    const existing = groups.get(key);
 21→    if (existing) {
 22→      existing.push(cp);
 23→    } else {
 24→      groups.set(key, [cp]);
 25→    }
 26→  }
 27→
 28→  return Array.from(groups.entries()).map(([key, items]) => {
 29→    const d = new Date(key);
 30→    const dayName = d.toLocaleDateString("en-US", { weekday: "long" });
 31→    const day = d.getDate();
 32→    const month = d.toLocaleDateString("en-US", { month: "short" });
 33→    return { label: `${dayName} ${day} ${month}`, items };
 34→  });
 35→}
