 41→pub fn list_branches(repo: &Repository) -> Result<Vec<BranchInfo>, String> {
 42→    let mut branches = Vec::new();
 43→    let head = repo.head().ok();
 44→    let head_name = head
 45→        .as_ref()
 46→        .and_then(|h| h.shorthand().map(|s| s.to_string()));
 47→
 48→    // Get the HEAD branch's commit tree for diffing
 49→    let head_tree = head
 50→        .as_ref()
 51→        .and_then(|h| h.peel_to_commit().ok())
 52→        .and_then(|c| c.tree().ok());
 53→
 54→    let git_branches = repo
 55→        .branches(Some(git2::BranchType::Local))
 56→        .map_err(|e| format!("Failed to list branches: {}", e))?;
 57→
 58→    for branch_result in git_branches {
 59→        let (branch, _) = branch_result.map_err(|e| format!("Branch error: {}", e))?;
 60→        if let Some(name) = branch.name().ok().flatten() {
 61→            // Skip entire/ internal branches
 62→            if name.starts_with("entire/") {
 63→                continue;
 64→            }
 65→            let is_head = head_name.as_deref() == Some(name);
 66→            let (additions, deletions) = if is_head {
 67→                (0, 0)
 68→            } else {
 69→                compute_branch_diff_stats(repo, &branch, head_tree.as_ref())
 70→            };
 71→            branches.push(BranchInfo {
 72→                is_head,
 73→                name: name.to_string(),
 74→                checkpoint_count: 0, // TODO: count from checkpoint branch
 75→                additions,
 76→                deletions,
 77→            });
 78→        }
 79→    }
 80→
 81→    Ok(branches)
 82→}
