 60→/// Create a new PTY session, spawn the child process, and start
 61→/// streaming output to the frontend via Tauri events.
 62→#[tauri::command]
 63→pub fn pty_create(
 64→    app: AppHandle,
 65→    working_dir: String,
 66→    command: Option<String>,
 67→    args: Option<Vec<String>>,
 68→    initial_input: Option<String>,
 69→    state: State<'_, Mutex<PtyState>>,
 70→) -> Result<String, String> {
 71→    let pty_system = native_pty_system();
 72→
 73→    let pair = pty_system
 74→        .openpty(PtySize {
 75→            rows: 24,
 76→            cols: 80,
 77→            pixel_width: 0,
 78→            pixel_height: 0,
 79→        })
 80→        .map_err(|e| format!("Failed to open PTY: {}", e))?;
 81→
 82→    let resolved = resolve_command(command.as_deref());
 83→
 84→    let mut cmd = if let Some(program) = resolved {
 85→        let mut c = CommandBuilder::new(program);
 86→        if let Some(ref extra_args) = args {
