 51→    } catch {
 52→      // WebGL not available — fall back to canvas renderer (automatic)
 53→    }
 54→
 55→    fitAddon.fit();
 56→    terminalRef.current = terminal;
 57→    fitAddonRef.current = fitAddon;
 58→
 59→    // Send initial resize to backend
 60→    invoke("pty_resize", {
 61→      sessionId,
